import{_ as t}from"./plugin-vue_export-helper-x3n3nnut.js";import{r as p,o,c as l,a as s,b as n,d as e,e as c}from"./app-AMUHiwF7.js";const i={},u=s("h1",{id:"python面向对象-九",tabindex:"-1"},[s("a",{class:"header-anchor",href:"#python面向对象-九","aria-hidden":"true"},"#"),n(" Python面向对象(九)")],-1),d={href:"https://blog.csdn.net/m0_66570338/article/details/128714062",target:"_blank",rel:"noopener noreferrer"},r={href:"https://download.csdn.net/download/m0_66570338/90058604",target:"_blank",rel:"noopener noreferrer"},k=c(`<h3 id="一-什么是面向对象" tabindex="-1"><a class="header-anchor" href="#一-什么是面向对象" aria-hidden="true">#</a> 一.什么是面向对象</h3><blockquote><p>万物皆对象</p></blockquote><ul><li>现实世界的事物都有属性和行为,可在程序中抽离为类来描述现实世界的事物属性和行为。 <img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/e1cd967b241139fb3016768418eb89e9.png" alt="img" loading="lazy"></li><li>使用<strong>类</strong>充当程序内现实事物的“设计图纸”，基于图纸(类)生产实体（对象），由对象做具体的工作，称之为：<strong>面向对象编程</strong></li><li>在现实世界中，生产事物：先设计图纸，完成功能属性分析，再批量制造 <img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/ff7feca7800b0e823b76cef27da01b42.png" alt="img" loading="lazy"></li><li>在程序中，通过类作为事物的设计图纸，记录事物的属性和行为 <img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/6d185193b75bb92f6aa70bbeb7b10d0b.png" alt="img" loading="lazy"></li><li>基于类(设计图纸)构建(生产)闹钟对象 <img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/f695cba9bcf0f4f8478c48fd69a4b349.png" alt="img" loading="lazy"></li></ul><hr><h3 id="二-类与对象" tabindex="-1"><a class="header-anchor" href="#二-类与对象" aria-hidden="true">#</a> 二.类与对象</h3><blockquote><p>使用类封装属性，基于类创建出一个个的对象来使用</p></blockquote><h4 id="_1-基本语法" tabindex="-1"><a class="header-anchor" href="#_1-基本语法" aria-hidden="true">#</a> (1) 基本语法</h4><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># 创建类</span>
<span class="token keyword">class</span> 类名称<span class="token punctuation">:</span>
    类的属性<span class="token punctuation">(</span>成员变量<span class="token punctuation">)</span>
    
    类的行为<span class="token punctuation">(</span>成员方法<span class="token punctuation">)</span>
    
<span class="token comment"># 基于类创建对象</span>
对象名 <span class="token operator">=</span> 类名称<span class="token punctuation">(</span><span class="token punctuation">)</span>

<span class="token comment"># 调用</span>
对象名<span class="token punctuation">.</span>成员变量
对象名<span class="token punctuation">.</span>成员方法<span class="token punctuation">(</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>class</code>:关键字,表示要定义类了</li><li><code>类的属性</code>:定义在类中的变量(成员变量) -&gt; 事物的属性</li><li><code>类的行为</code>:定义在类中的函数(成员方法) -&gt; 事物的行为</li></ul><h4 id="_2-使用示例" tabindex="-1"><a class="header-anchor" href="#_2-使用示例" aria-hidden="true">#</a> (2) 使用示例</h4><figure><img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/ccd43c6dda07c81b443e46b6e0a8ed21.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><ul><li>设计表格即<code>设计类(class)</code>：</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">class</span> <span class="token class-name">Student</span><span class="token punctuation">:</span>
    name <span class="token operator">=</span> <span class="token boolean">None</span>  <span class="token comment"># 姓名</span>
    sex <span class="token operator">=</span> <span class="token boolean">None</span>  <span class="token comment"># 性别</span>
    country <span class="token operator">=</span> <span class="token boolean">None</span>  <span class="token comment"># 国籍</span>
    native_place <span class="token operator">=</span> <span class="token boolean">None</span>  <span class="token comment"># 籍贯</span>
    age <span class="token operator">=</span> <span class="token boolean">None</span>  <span class="token comment"># 年龄</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>打印表格即<code>创建对象</code>：</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>stu_1 <span class="token operator">=</span> Student<span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token comment"># 一张</span>
stu_2 <span class="token operator">=</span> Student<span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token comment"># 两张</span>
stu_3 <span class="token operator">=</span> Student<span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token comment"># 三张</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>填写表格即<code>使用对象(为属性赋值)</code>:</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>stu_1<span class="token punctuation">.</span>name <span class="token operator">=</span> <span class="token string">&quot;李白&quot;</span>
stu_2<span class="token punctuation">.</span>name <span class="token operator">=</span> <span class="token string">&quot;观止&quot;</span>
stu_3<span class="token punctuation">.</span>name <span class="token operator">=</span> <span class="token string">&quot;罗辑&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>概览: <img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/e3600f037eeea63d5555ecb539b249e8.png" alt="img" loading="lazy"></li></ul><h4 id="_3-成员变量和成员方法" tabindex="-1"><a class="header-anchor" href="#_3-成员变量和成员方法" aria-hidden="true">#</a> (3) 成员变量和成员方法</h4><h5 id="_3-1-成员变量" tabindex="-1"><a class="header-anchor" href="#_3-1-成员变量" aria-hidden="true">#</a> (3.1) 成员变量</h5><ul><li>定义在类内部的变量称之为成员变量，用法与正常变量一致。</li></ul><h5 id="_3-2-成员方法" tabindex="-1"><a class="header-anchor" href="#_3-2-成员方法" aria-hidden="true">#</a> (3.2) 成员方法</h5><blockquote><p>定义在类内部的函数称之为方法，与函数存在细微区别。</p></blockquote><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># 函数</span>
<span class="token comment"># 形参可以为0-N个</span>
<span class="token keyword">def</span> 函数名<span class="token punctuation">(</span>形参<span class="token number">1</span><span class="token punctuation">,</span>形参<span class="token number">2</span><span class="token punctuation">,</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">,</span>形参N<span class="token punctuation">)</span><span class="token punctuation">:</span>
    函数体

<span class="token comment"># 方法</span>
<span class="token comment"># 形参可以为0-N个</span>
<span class="token comment"># self关键字必须填写</span>
<span class="token keyword">def</span> 方法名<span class="token punctuation">(</span>self<span class="token punctuation">,</span>形参<span class="token number">1</span><span class="token punctuation">,</span>形参<span class="token number">2</span><span class="token punctuation">,</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">,</span>形参N<span class="token punctuation">)</span><span class="token punctuation">:</span>
    方法体
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>self</code>关键字在成员方法定义的时候<strong>必须填写</strong>，表示类对象自身</li><li>在方法内部，想要访问类的成员变量，必须使用self</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">class</span> <span class="token class-name">Student</span><span class="token punctuation">:</span>
    name <span class="token operator">=</span> <span class="token boolean">None</span>  
    
    <span class="token comment"># 调用say_hi1时正常打印</span>
    <span class="token keyword">def</span> <span class="token function">say_hi1</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string-interpolation"><span class="token string">f&quot;大家好，我叫</span><span class="token interpolation"><span class="token punctuation">{</span>self<span class="token punctuation">.</span>name<span class="token punctuation">}</span></span><span class="token string">&quot;</span></span><span class="token punctuation">)</span> 
    
    <span class="token comment"># 调用say_hi2时报错，&#39;name&#39; is not defined</span>
    <span class="token keyword">def</span> <span class="token function">say_hi2</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string-interpolation"><span class="token string">f&quot;大家好，我叫</span><span class="token interpolation"><span class="token punctuation">{</span>name<span class="token punctuation">}</span></span><span class="token string">&quot;</span></span><span class="token punctuation">)</span> 
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>当我们使用对象调用方法的时，self会自动被python传入,尽管在参数列表中，但是传参的时候可以忽略它。</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># 定义</span>
<span class="token keyword">class</span> <span class="token class-name">Student</span><span class="token punctuation">:</span>
    name <span class="token operator">=</span> <span class="token boolean">None</span>

    <span class="token keyword">def</span> <span class="token function">say_hi</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> msg<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string-interpolation"><span class="token string">f&quot;大家好，我是</span><span class="token interpolation"><span class="token punctuation">{</span>msg<span class="token punctuation">}</span></span><span class="token string">&quot;</span></span><span class="token punctuation">)</span>

<span class="token comment"># 创建</span>
stu_1 <span class="token operator">=</span> Student<span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token comment"># 通过对象名调用</span>
stu_1<span class="token punctuation">.</span>say_hi<span class="token punctuation">(</span><span class="token string">&quot;练习两年半的偶像实习生&quot;</span><span class="token punctuation">)</span>
<span class="token comment"># 打印 大家好，我是练习两年半的偶像实习生</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_4-构造方法" tabindex="-1"><a class="header-anchor" href="#_4-构造方法" aria-hidden="true">#</a> (4) 构造方法</h4><blockquote><p>通过传参的形式快速对属性赋值</p></blockquote><ul><li>正常情况下,为对象的属性赋值需要依次进行</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># 定义类</span>
<span class="token keyword">class</span> <span class="token class-name">Student</span><span class="token punctuation">:</span>
    name <span class="token operator">=</span> <span class="token boolean">None</span>  <span class="token comment"># 姓名</span>
    sex <span class="token operator">=</span> <span class="token boolean">None</span>  <span class="token comment"># 性别</span>
    age <span class="token operator">=</span> <span class="token boolean">None</span>  <span class="token comment"># 年龄</span>

<span class="token comment"># 创建对象</span>
stu_1 <span class="token operator">=</span> Student<span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token comment"># 为对象赋值</span>
stu_1<span class="token punctuation">.</span>name <span class="token operator">=</span> <span class="token string">&quot;李白&quot;</span>
stu_1<span class="token punctuation">.</span>sex <span class="token operator">=</span> <span class="token string">&quot;男&quot;</span>
stu_1<span class="token punctuation">.</span>age <span class="token operator">=</span> <span class="token number">1000</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>在类可以使用：<code>__init__()</code>方法，即构造方法,快速为对象赋值。</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># 定义类</span>
<span class="token keyword">class</span> <span class="token class-name">Student</span><span class="token punctuation">:</span>
    name <span class="token operator">=</span> <span class="token boolean">None</span>  <span class="token comment"># 姓名</span>
    sex <span class="token operator">=</span> <span class="token boolean">None</span>  <span class="token comment"># 性别</span>
    age <span class="token operator">=</span> <span class="token boolean">None</span>  <span class="token comment"># 年龄</span>

    <span class="token keyword">def</span> <span class="token function">__init__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> name<span class="token punctuation">,</span> sex<span class="token punctuation">,</span> age<span class="token punctuation">)</span><span class="token punctuation">:</span>
        self<span class="token punctuation">.</span>name <span class="token operator">=</span> name
        self<span class="token punctuation">.</span>sex <span class="token operator">=</span> sex
        self<span class="token punctuation">.</span>age <span class="token operator">=</span> age

<span class="token comment"># 创建对象并赋值</span>
stu_1 <span class="token operator">=</span> Student<span class="token punctuation">(</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;男&quot;</span><span class="token punctuation">,</span> <span class="token number">1000</span><span class="token punctuation">)</span>

<span class="token comment"># 简化形式：可以省略成员属性定义,但仍可调用</span>
<span class="token keyword">class</span> <span class="token class-name">Student</span><span class="token punctuation">:</span>

    <span class="token keyword">def</span> <span class="token function">__init__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> name<span class="token punctuation">,</span> sex<span class="token punctuation">,</span> age<span class="token punctuation">)</span><span class="token punctuation">:</span>
        self<span class="token punctuation">.</span>name <span class="token operator">=</span> name  <span class="token comment"># 姓名</span>
        self<span class="token punctuation">.</span>sex <span class="token operator">=</span> sex  <span class="token comment"># 性别</span>
        self<span class="token punctuation">.</span>age <span class="token operator">=</span> age  <span class="token comment"># 年龄</span>

<span class="token comment"># 创建对象并赋值</span>
stu_1 <span class="token operator">=</span> Student<span class="token punctuation">(</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;男&quot;</span><span class="token punctuation">,</span> <span class="token number">1000</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>在创建类对象（构造类）的时候，会自动执行，将传入参数自动传递给<code>__init__</code>方法使用。</li><li>构造方法也是成员方法，定义时也需要在参数列表中提供：<code>self</code></li><li>变量定义在构造方法内部，如果要成为成员变量，需要用self来表示，例如<code>self.name</code></li><li>使用了构造方法，创建对象时必须传参否则会报错 <img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/62fda5cc61db9cc89342cb8ddf9ead2a.png" alt="img" loading="lazy"></li></ul><h4 id="_5-魔术方法" tabindex="-1"><a class="header-anchor" href="#_5-魔术方法" aria-hidden="true">#</a> (5) 魔术方法</h4><blockquote><p>Python类内置的类方法，各自有各自特殊的功能</p></blockquote><ul><li>魔术方法非常多，我们学习几个常用的即可。</li></ul><table><thead><tr><th style="text-align:left;">方法</th><th style="text-align:left;">功能</th></tr></thead><tbody><tr><td style="text-align:left;"><code>__init__</code></td><td style="text-align:left;">构造方法，可用于创建类对象的时候设置初始化行为</td></tr><tr><td style="text-align:left;"><code>__str__</code></td><td style="text-align:left;">字符串方法，用于实现类对象转字符串的行为</td></tr><tr><td style="text-align:left;"><code>__lt__</code></td><td style="text-align:left;">用于2个类对象进行小于(&lt;)或大于(&gt;)比较</td></tr><tr><td style="text-align:left;"><code>__le__</code></td><td style="text-align:left;">用于2个类对象进行小于等于(&lt;=)或大于等于(&gt;=)比较</td></tr><tr><td style="text-align:left;"><code>__eq__</code></td><td style="text-align:left;">用于2个类对象进行相等(==)比较</td></tr></tbody></table><h5 id="_5-1-str-方法" tabindex="-1"><a class="header-anchor" href="#_5-1-str-方法" aria-hidden="true">#</a> (5.1)<code>__str__</code>方法</h5><ul><li>当直接打印类对象时，打印的是对象的内存地址，用处不大。</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">class</span> <span class="token class-name">Student</span><span class="token punctuation">:</span>

    <span class="token keyword">def</span> <span class="token function">__init__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> name<span class="token punctuation">,</span> age<span class="token punctuation">)</span><span class="token punctuation">:</span>
        self<span class="token punctuation">.</span>name <span class="token operator">=</span> name  <span class="token comment"># 姓名</span>
        self<span class="token punctuation">.</span>age <span class="token operator">=</span> age  <span class="token comment"># 年龄</span>

stu_1 <span class="token operator">=</span> Student<span class="token punctuation">(</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token number">1000</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>stu_1<span class="token punctuation">)</span>
<span class="token comment"># 打印 &lt;__main__.Student object at 0x0000024D8C6195D0&gt;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>我们可以通过<code>__str__</code>方法，自定义控制打印类对象时输出的内容。</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">class</span> <span class="token class-name">Student</span><span class="token punctuation">:</span>

    <span class="token keyword">def</span> <span class="token function">__init__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> name<span class="token punctuation">,</span> age<span class="token punctuation">)</span><span class="token punctuation">:</span>
        self<span class="token punctuation">.</span>name <span class="token operator">=</span> name  <span class="token comment"># 姓名</span>
        self<span class="token punctuation">.</span>age <span class="token operator">=</span> age  <span class="token comment"># 年龄</span>
        
	<span class="token comment"># 自定义打印输出内容</span>
    <span class="token keyword">def</span> <span class="token function">__str__</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">return</span> <span class="token string-interpolation"><span class="token string">f&quot;Student对象,name=</span><span class="token interpolation"><span class="token punctuation">{</span>self<span class="token punctuation">.</span>name<span class="token punctuation">}</span></span><span class="token string">,age=</span><span class="token interpolation"><span class="token punctuation">{</span>self<span class="token punctuation">.</span>age<span class="token punctuation">}</span></span><span class="token string">&quot;</span></span>

stu_1 <span class="token operator">=</span> Student<span class="token punctuation">(</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token number">1000</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>stu_1<span class="token punctuation">)</span>
<span class="token comment"># 打印 Student对象,name=李白,age=1000</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_5-2-lt-方法" tabindex="-1"><a class="header-anchor" href="#_5-2-lt-方法" aria-hidden="true">#</a> (5.2)<code>__lt__</code>方法</h5><ul><li>直接对2个对象进行比较是不可以的，会报错。</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">class</span> <span class="token class-name">Student</span><span class="token punctuation">:</span>

    <span class="token keyword">def</span> <span class="token function">__init__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> name<span class="token punctuation">,</span> age<span class="token punctuation">)</span><span class="token punctuation">:</span>
        self<span class="token punctuation">.</span>name <span class="token operator">=</span> name  <span class="token comment"># 姓名</span>
        self<span class="token punctuation">.</span>age <span class="token operator">=</span> age  <span class="token comment"># 年龄</span>


stu_1 <span class="token operator">=</span> Student<span class="token punctuation">(</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token number">1000</span><span class="token punctuation">)</span>
stu_2 <span class="token operator">=</span> Student<span class="token punctuation">(</span><span class="token string">&quot;罗辑&quot;</span><span class="token punctuation">,</span> <span class="token number">300</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>stu_1 <span class="token operator">&gt;</span> stu_2<span class="token punctuation">)</span> <span class="token comment"># 报错</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/fd8620c1756e992960b65282f817c856.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><ul><li>在类中实现<code>__lt__</code>方法即可完成：小于符号 和 大于符号 2种比较</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">class</span> <span class="token class-name">Student</span><span class="token punctuation">:</span>

    <span class="token keyword">def</span> <span class="token function">__init__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> name<span class="token punctuation">,</span> age<span class="token punctuation">)</span><span class="token punctuation">:</span>
        self<span class="token punctuation">.</span>name <span class="token operator">=</span> name  <span class="token comment"># 姓名</span>
        self<span class="token punctuation">.</span>age <span class="token operator">=</span> age  <span class="token comment"># 年龄</span>

    <span class="token keyword">def</span> <span class="token function">__lt__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> other<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">return</span> self<span class="token punctuation">.</span>age <span class="token operator">&lt;</span> other<span class="token punctuation">.</span>age


stu_1 <span class="token operator">=</span> Student<span class="token punctuation">(</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token number">1000</span><span class="token punctuation">)</span>
stu_2 <span class="token operator">=</span> Student<span class="token punctuation">(</span><span class="token string">&quot;罗辑&quot;</span><span class="token punctuation">,</span> <span class="token number">300</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>stu_1 <span class="token operator">&gt;</span> stu_2<span class="token punctuation">)</span> <span class="token comment"># 打印 True</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_5-3-le-方法" tabindex="-1"><a class="header-anchor" href="#_5-3-le-方法" aria-hidden="true">#</a> (5.3) <code>__le__</code>方法</h5><ul><li>在类中实现<code>__le__</code>方法即可完成：小于等于符号 和 大于等于符号 2种比较，否则会报错</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">class</span> <span class="token class-name">Student</span><span class="token punctuation">:</span>

    <span class="token keyword">def</span> <span class="token function">__init__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> name<span class="token punctuation">,</span> age<span class="token punctuation">)</span><span class="token punctuation">:</span>
        self<span class="token punctuation">.</span>name <span class="token operator">=</span> name  <span class="token comment"># 姓名</span>
        self<span class="token punctuation">.</span>age <span class="token operator">=</span> age  <span class="token comment"># 年龄</span>

    <span class="token keyword">def</span> <span class="token function">__le__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> other<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">return</span> self<span class="token punctuation">.</span>age <span class="token operator">&lt;=</span> other<span class="token punctuation">.</span>age


stu_1 <span class="token operator">=</span> Student<span class="token punctuation">(</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token number">1000</span><span class="token punctuation">)</span>
stu_2 <span class="token operator">=</span> Student<span class="token punctuation">(</span><span class="token string">&quot;罗辑&quot;</span><span class="token punctuation">,</span> <span class="token number">1000</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>stu_1 <span class="token operator">&lt;=</span> stu_2<span class="token punctuation">)</span>  <span class="token comment"># True</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>stu_1 <span class="token operator">&gt;=</span> stu_2<span class="token punctuation">)</span>  <span class="token comment"># True</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_5-4-eq-方法" tabindex="-1"><a class="header-anchor" href="#_5-4-eq-方法" aria-hidden="true">#</a> (5.4) <code>__eq__</code>方法</h5><ul><li>不实现<code>__eq__</code>方法，对象之间可以比较，但是是比较内存地址，但是不同对象==比较一定是False结果。</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">class</span> <span class="token class-name">Student</span><span class="token punctuation">:</span>

    <span class="token keyword">def</span> <span class="token function">__init__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> name<span class="token punctuation">,</span> age<span class="token punctuation">)</span><span class="token punctuation">:</span>
        self<span class="token punctuation">.</span>name <span class="token operator">=</span> name  <span class="token comment"># 姓名</span>
        self<span class="token punctuation">.</span>age <span class="token operator">=</span> age  <span class="token comment"># 年龄</span>


stu_1 <span class="token operator">=</span> Student<span class="token punctuation">(</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token number">1000</span><span class="token punctuation">)</span>
stu_2 <span class="token operator">=</span> Student<span class="token punctuation">(</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token number">666</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>stu_1 <span class="token operator">==</span> stu_2<span class="token punctuation">)</span>  <span class="token comment"># False</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>实现了<code>__eq__</code>方法，就可以按照自己的想法来决定2个对象是否相等了。</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">class</span> <span class="token class-name">Student</span><span class="token punctuation">:</span>

    <span class="token keyword">def</span> <span class="token function">__init__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> name<span class="token punctuation">,</span> age<span class="token punctuation">)</span><span class="token punctuation">:</span>
        self<span class="token punctuation">.</span>name <span class="token operator">=</span> name  <span class="token comment"># 姓名</span>
        self<span class="token punctuation">.</span>age <span class="token operator">=</span> age  <span class="token comment"># 年龄</span>
	<span class="token comment"># 自定义比较规则</span>
    <span class="token keyword">def</span> <span class="token function">__eq__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> other<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">return</span> self<span class="token punctuation">.</span>name <span class="token operator">==</span> other<span class="token punctuation">.</span>name


stu_1 <span class="token operator">=</span> Student<span class="token punctuation">(</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token number">1000</span><span class="token punctuation">)</span>
stu_2 <span class="token operator">=</span> Student<span class="token punctuation">(</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token number">666</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>stu_1 <span class="token operator">==</span> stu_2<span class="token punctuation">)</span>  <span class="token comment"># True</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h3 id="三-三大特性" tabindex="-1"><a class="header-anchor" href="#三-三大特性" aria-hidden="true">#</a> 三.三大特性</h3><blockquote><p>面向对象包含3大主要特性：封装,继承,多态</p></blockquote><h4 id="_1-封装" tabindex="-1"><a class="header-anchor" href="#_1-封装" aria-hidden="true">#</a> (1) 封装</h4><blockquote><p>将现实世界事物的属性和行为+在类中描述为成员变量和成员方法,完成程序对现实世界事物的描述</p></blockquote><figure><img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/d49a8ff5c489b0989dae1e25622d4090.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><ul><li>现实世界中的事物，有属性和行为。但是不代表这些属性和行为都是开放给用户使用的 <img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/dfba9b4b5319cdc7975943410a8a1878.png" alt="img" loading="lazy"></li></ul><h5 id="_1-1-私有成员" tabindex="-1"><a class="header-anchor" href="#_1-1-私有成员" aria-hidden="true">#</a> (1.1) 私有成员</h5><blockquote><p>在类中提供仅供内部使用的属性和方法，无法被对象调用</p></blockquote><figure><img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/9eb922235b84e4ef1953a2126491751e.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><ul><li>基本语法： <ul><li>私有成员变量：变量名以__开头（2个下划线）</li><li>私有成员方法：方法名以__开头（2个下划线）</li></ul></li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">class</span> <span class="token class-name">Student</span><span class="token punctuation">:</span>
    name <span class="token operator">=</span> <span class="token boolean">None</span>  <span class="token comment"># 普通成员变量</span>
    __age <span class="token operator">=</span> <span class="token boolean">None</span>  <span class="token comment"># 私有成员变量</span>
    
    <span class="token comment"># 普通成员方法</span>
    <span class="token keyword">def</span> <span class="token function">say_hi</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;你好&quot;</span><span class="token punctuation">)</span>

    <span class="token comment"># 私有成员方法</span>
    <span class="token keyword">def</span> <span class="token function">__DNA</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;DNA数量&quot;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>仅在成员内部可以使用</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">class</span> <span class="token class-name">Student</span><span class="token punctuation">:</span>
    name <span class="token operator">=</span> <span class="token boolean">None</span>  <span class="token comment"># 普通成员变量</span>
    __age <span class="token operator">=</span> <span class="token number">16</span>  <span class="token comment"># 私有成员变量</span>

    <span class="token comment"># 普通成员方法</span>
    <span class="token keyword">def</span> <span class="token function">show</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span> 
        self<span class="token punctuation">.</span>__check<span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token comment"># 在类中使用私有成员变量</span>
        <span class="token keyword">if</span> self<span class="token punctuation">.</span>__age <span class="token operator">&gt;</span> <span class="token number">18</span><span class="token punctuation">:</span> <span class="token comment"># 在类中使用私有成员变量</span>
            <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;成年人&quot;</span><span class="token punctuation">)</span>
        <span class="token keyword">else</span><span class="token punctuation">:</span>
            <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;未成年&quot;</span><span class="token punctuation">)</span>

    <span class="token comment"># 私有成员方法</span>
    <span class="token keyword">def</span> <span class="token function">__check</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;自检&quot;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-继承" tabindex="-1"><a class="header-anchor" href="#_2-继承" aria-hidden="true">#</a> (2) 继承</h4><blockquote><p>一个类继承另外一个类的所有成员变量和成员方法(不含私有)</p></blockquote><figure><img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/4b5fd02a65b1ad1c4f470791ebb0d547.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><h5 id="_2-1-单继承" tabindex="-1"><a class="header-anchor" href="#_2-1-单继承" aria-hidden="true">#</a> (2.1) 单继承</h5><ul><li>基本语法:</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">class</span> 类名<span class="token punctuation">(</span>父类名<span class="token punctuation">)</span><span class="token punctuation">:</span>
    类内容体
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>基本使用:</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># 待继承的类</span>
<span class="token keyword">class</span> <span class="token class-name">Phone</span><span class="token punctuation">:</span>
    producer <span class="token operator">=</span> <span class="token string">&quot;apple&quot;</span>  <span class="token comment"># 厂商</span>

    <span class="token keyword">def</span> <span class="token function">call_by_4g</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;4g通话&quot;</span><span class="token punctuation">)</span>

<span class="token comment"># 继承Phone</span>
<span class="token keyword">class</span> <span class="token class-name">Phone2022</span><span class="token punctuation">(</span>Phone<span class="token punctuation">)</span><span class="token punctuation">:</span>
    face_id <span class="token operator">=</span> <span class="token boolean">True</span>  <span class="token comment"># 面部识别</span>

    <span class="token keyword">def</span> <span class="token function">call_by_5g</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;2022最新5G通话&quot;</span><span class="token punctuation">)</span>
<span class="token comment"># 创建对象</span>
phone <span class="token operator">=</span> Phone2022<span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token comment"># 使用</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>phone<span class="token punctuation">.</span>producer<span class="token punctuation">)</span> <span class="token comment"># 可调用 继承自Phone的成员变量</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>phone<span class="token punctuation">.</span>face_id<span class="token punctuation">)</span> <span class="token comment"># 可调用 自身的成员变量</span>
phone<span class="token punctuation">.</span>call_by_4g<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment"># 可调用 继承自Phone的成员方法</span>
phone<span class="token punctuation">.</span>call_by_5g<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment"># 可调用 自身的成员方法</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_2-2-多继承" tabindex="-1"><a class="header-anchor" href="#_2-2-多继承" aria-hidden="true">#</a> (2.2) 多继承</h5><ul><li>一个类也可以继承多个类</li><li>多个父类中，如果有同名的成员，默认以继承顺序（从左到右）为优先级。即:后继承的被先继承的覆盖</li><li>基本语法:</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">class</span> 类名<span class="token punctuation">(</span>父类<span class="token number">1</span><span class="token punctuation">,</span>父类<span class="token number">2</span><span class="token punctuation">,</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">,</span>父类N<span class="token punctuation">)</span><span class="token punctuation">:</span>
    类内容体
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>使用示例:</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">class</span> <span class="token class-name">Phone</span><span class="token punctuation">:</span>
    producer <span class="token operator">=</span> <span class="token string">&quot;apple&quot;</span>  <span class="token comment"># 厂商</span>

<span class="token keyword">class</span> <span class="token class-name">Camera</span><span class="token punctuation">:</span>
    producer <span class="token operator">=</span> <span class="token string">&quot;suoni&quot;</span>  <span class="token comment"># 厂商</span>

<span class="token keyword">class</span> <span class="token class-name">Phone2022</span><span class="token punctuation">(</span>Phone<span class="token punctuation">,</span> Camera<span class="token punctuation">)</span><span class="token punctuation">:</span>
    face_id <span class="token operator">=</span> <span class="token boolean">True</span>  <span class="token comment"># 面部识别</span>

    <span class="token keyword">def</span> <span class="token function">call_by_5g</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;2022最新5G通话&quot;</span><span class="token punctuation">)</span>

phone <span class="token operator">=</span> Phone2022<span class="token punctuation">(</span><span class="token punctuation">)</span>

<span class="token keyword">print</span><span class="token punctuation">(</span>phone<span class="token punctuation">.</span>producer<span class="token punctuation">)</span>  <span class="token comment"># 打印结果为apple而非suoni</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_2-3-复写" tabindex="-1"><a class="header-anchor" href="#_2-3-复写" aria-hidden="true">#</a> (2.3) 复写</h5><ul><li>子类继承父类的成员属性和成员方法后，如果对其“不满意”，那么可以进行复写。即：在子类中重新定义同名的属性或方法。</li><li>一旦复写父类成员，那么类对象调用成员的时候，就会调用复写后的新成员</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">class</span> <span class="token class-name">Phone2021</span><span class="token punctuation">:</span>
    producer <span class="token operator">=</span> <span class="token string">&quot;apple&quot;</span>  <span class="token comment"># 厂商</span>

    <span class="token keyword">def</span> <span class="token function">call_by_5g</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;2021版5G通话&quot;</span><span class="token punctuation">)</span>


<span class="token keyword">class</span> <span class="token class-name">Phone2022</span><span class="token punctuation">(</span>Phone2021<span class="token punctuation">)</span><span class="token punctuation">:</span>
    face_id <span class="token operator">=</span> <span class="token boolean">True</span>  <span class="token comment"># 面部识别</span>

    <span class="token keyword">def</span> <span class="token function">call_by_5g</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;2022升级版5G通话&quot;</span><span class="token punctuation">)</span>


phone <span class="token operator">=</span> Phone2022<span class="token punctuation">(</span><span class="token punctuation">)</span>

phone<span class="token punctuation">.</span>call_by_5g<span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 2022升级版5G通话</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><p>如果需要使用被复写的父类的成员,只能在子类内通过如下方式调用父类的同名成员:</p><ul><li>方式一：使用父类名调用</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>使用成员变量：父类名<span class="token punctuation">.</span>成员变量
使用成员方法：父类名<span class="token punctuation">.</span>成员方法<span class="token punctuation">(</span>self<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>方式二：使用<code>super()</code>调用</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>使用成员变量：<span class="token builtin">super</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span>成员变量
使用成员方法：<span class="token builtin">super</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span>成员方法<span class="token punctuation">(</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>使用示例：</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">class</span> <span class="token class-name">Phone2021</span><span class="token punctuation">:</span>
    producer <span class="token operator">=</span> <span class="token string">&quot;apple&quot;</span>  <span class="token comment"># 厂商</span>

    <span class="token keyword">def</span> <span class="token function">call_by_5g</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;2021版5G通话&quot;</span><span class="token punctuation">)</span>


<span class="token keyword">class</span> <span class="token class-name">Phone2022</span><span class="token punctuation">(</span>Phone2021<span class="token punctuation">)</span><span class="token punctuation">:</span>
    face_id <span class="token operator">=</span> <span class="token boolean">True</span>  <span class="token comment"># 面部识别</span>

    <span class="token keyword">def</span> <span class="token function">call_by_5g</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token comment"># 方式一调用</span>
        <span class="token keyword">print</span><span class="token punctuation">(</span>Phone2021<span class="token punctuation">.</span>producer<span class="token punctuation">)</span>  <span class="token comment"># 打印 apple</span>
        Phone2021<span class="token punctuation">.</span>call_by_5g<span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token comment"># 打印 2021版5G通话</span>
        <span class="token comment"># 方式二调用</span>
        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">super</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span>producer<span class="token punctuation">)</span><span class="token comment"># 打印 apple</span>
        <span class="token builtin">super</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span>call_by_5g<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token comment"># 打印 2021版5G通话</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ul><h4 id="_3-多态" tabindex="-1"><a class="header-anchor" href="#_3-多态" aria-hidden="true">#</a> (3) 多态</h4><blockquote><p>多种状态，即完成某个行为时，使用不同的对象会得到不同的状态</p></blockquote><figure><img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/90d55d003801b91b2753544fb4579818.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><ul><li>多态常作用在继承关系上，函数(方法)形参声明接收父类对象，实际传入父类的子类对象进行工作，即 <ul><li>以父类做定义声明</li><li>以子类做实际工作</li><li>用以获得同一行为, 不同状态 <img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/f1e34714421640e3c75337287eb82cf4.png" alt="img" loading="lazy"></li></ul></li></ul><h5 id="_3-1-抽象类-接口" tabindex="-1"><a class="header-anchor" href="#_3-1-抽象类-接口" aria-hidden="true">#</a> (3.1) 抽象类(接口)</h5><blockquote><p>抽象类就好比定义一个标准，包含了一些抽象的方法，要求子类必须实现</p></blockquote><figure><img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/f0aa62f8b93511815e9390aa8f015efd.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><ul><li><p>抽象类：包含抽象方法的类</p></li><li><p>抽象方法：没有具体实现的方法（只含pass）称之为抽象方法</p></li><li><p><code>pass</code>是占位语句，用来保证函数（方法）或类定义的完整性，表示无内容，空的意思 <img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/81f0dfb915be516f854988b5d30cdf2e.png" alt="img" loading="lazy"></p></li><li><p>多用于做顶层设计（设计标准），以便子类做具体实现。是对子类的一种软性约束，要求子类必须复写（实现）父类的一些方法</p><p>并配合多态使用，获得不同的工作状态。</p></li></ul><h3 id="四-全文概览" tabindex="-1"><a class="header-anchor" href="#四-全文概览" aria-hidden="true">#</a> 四.全文概览</h3><figure><img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/cfc2851172a9d2e631da6d03f583b400.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure>`,99);function m(v,b){const a=p("ExternalLinkIcon");return o(),l("div",null,[u,s("blockquote",null,[s("p",null,[n("python学习之旅(九) 学习汇总入口"),s("a",d,[n("【Python】学习汇总(3万字+思维导图)"),e(a)]),n("、 笔记PDF下载："),s("a",r,[n("知识笔记：Python面向对象(九)"),e(a)]),n(" 文末附全文概览思维导图 写作不易，如果您觉得写的不错，欢迎给博主来一波点赞、收藏~让博主更有动力吧！")])]),k])}const _=t(i,[["render",m],["__file","09.面向对象.html.vue"]]);export{_ as default};
